export const acceptTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const taskId = req.params.id as string;
  const { result, comment } = req.body;

  try {
    logger.info('Accepting task', { requestId, taskId, result });

    // Get task first to find project
    const task = await taskService.getTaskById(taskId);
    if (!task) {
      return res.status(404).json({
        code: 404,
        msg: 'Task not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 权限校验：只有项目负责人或验收负责人可以验收任务
    const project = await Project.findByPk(task.project_id);
    if (!project) {
      return res.status(404).json({
        code: 404,
        msg: 'Project not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const currentUserId = (req as any).user?.id;
    if (project.manager_id !== currentUserId) {
      return res.status(403).json({
        code: 403,
        msg: 'Only project owner can accept tasks',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const updatedTask = await taskService.acceptTask(taskId, result, comment);

    // Add audit log
    await addAuditLog(req, 'accept_task', 'task', taskId);

    // TODO: 触发 task_acceptance_result 事件推送

    logger.info('Task accepted successfully', { requestId, taskId, result });
    res.json({
      code: 0,
      msg: `Task ${result === 'approved' ? 'approved' : 'rejected'} successfully`,
      data: updatedTask,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to accept task', error as Error, { requestId, taskId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

export const blockTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
