    timeout_hours: 24
    requires_approval: false
    next: "test_review"

  - id: test_review
    name: "测试评审"
    role: "test"
    action: "识别测试风险，评审可测试性"
    timeout_hours: 24
    requires_approval: false
    next: "summarize"

  - id: summarize
    name: "汇总评审结果"
    role: "product"
    action: "汇总所有反馈，更新PRD"
    decision:
