eProject = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const projectId = req.params.id as string;
  try {
    logger.info('Updating project', { requestId, projectId, body: req.body });

    // 验证请求数据
    const validation = validateUpdateProject(req.body);
    if (!validation.valid) {
      logger.warn('Project update validation failed', { requestId, projectId, errors: validation.errors });
      return res.status(400).json({
        code: 400,
        msg: validation.errors.join(', '),
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 权限校验：只有项目负责人或系统管理员可以修改项目配置
    const currentUserId = (req as any).user?.id;
    if (!currentUserId) {
      return res.status(401).json({
        code: 401,
        msg: 'Authentication required',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 检查用户权限（项目负责人或管理员）
    const canUpdate = await projectService.checkUpdatePermission(projectId, currentUserId, (req as any).user?.role);
    if (!canUpdate) {
      return res.status(403).json({
        code: 403,
        msg: 'Only project manager or system administrator can update project configuration',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const project = await projectService.updateProject(projectId, req.body);

    if (!project) {
      logger.warn(`Project not found for update with ID: ${projectId}`, { requestId, projectId });
      return res.status(404).json({
        code: 404,
        msg: 'Project not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // 触发 project_config_updated 事件推送
    eventEmitter.emit('project_config_updated', {
      project_id: projectId,
      updates: req.body,
      updated_by: (req as any).user?.id,
      updated_at: new Date().toISOString()
    });
    addAuditLog(req, 'update_config', 'project', projectId);

    logger.info('Project updated successfully', { requestId, projectId });
    res.json({
      code: 0,
      msg: 'Project updated successfully',
      data: project,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to update project', error as Error, { requestId, projectId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

