export const blockTask = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const taskId = req.params.id as string;
  const { block_reason, related_tasks, impact_scope } = req.body;

  try {
    logger.info('Blocking task', { requestId, taskId, block_reason });

    // Get task
    const task = await taskService.getTaskById(taskId);
    if (!task) {
      return res.status(404).json({
        code: 404,
        msg: 'Task not found',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    // Check permission: task assignee can block
    const currentUserId = (req as any).user?.id;
    if (task.assignee_id !== currentUserId) {
      return res.status(403).json({
        code: 403,
        msg: 'Only task assignee can report blocking',
        data: null,
        trace_id: requestId,
        timestamp: new Date().toISOString()
      });
    }

    const blockRecord = await taskService.blockTask(
      taskId,
      block_reason,
      related_tasks || [],
      impact_scope
    );

    // Add audit log
    await addAuditLog(req, 'block_task', 'task', taskId);

    // 触发 block_event_occurred 事件推送
    eventEmitter.emit('block_event_occurred', {
      task_id: taskId,
      block_reason,
      related_tasks,
      impact_scope,
      reported_by: (req as any).user?.id,
      reported_at: new Date().toISOString()
    });

    logger.info('Task blocked successfully', { requestId, taskId });
    res.json({
      code: 0,
      msg: 'Task blocked successfully',
      data: blockRecord,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to block task', error as Error, { requestId, taskId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

