/**
 * 获取团队效率统计
 * GET /api/statistics/efficiency
 */
export const getTeamEfficiency = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';

  try {
    logger.info('Fetching team efficiency statistics', { requestId });
    const data = await statsService.getTeamEfficiency();
    logger.info('Team efficiency fetched', { requestId });
    res.json({
      code: 0,
      msg: 'success',
      data,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch team efficiency', error as Error, { requestId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

/**
 * 获取跨项目统计
 * GET /api/statistics/cross-project
 */
export const getCrossProjectStatistics = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';
  const { date_from, date_to, agent_id, project_id } = req.query;

  try {
    logger.info('Fetching cross-project statistics', { requestId, date_from, date_to });
    const data = await statsService.getCrossProjectStats({
      dateFrom: date_from as string,
      dateTo: date_to as string,
      agentId: agent_id as string,
      projectId: project_id as string
    });
    logger.info('Cross-project statistics fetched', { requestId });
    res.json({
      code: 0,
      msg: 'success',
      data,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  } catch (error) {
    logger.error('Failed to fetch cross-project statistics', error as Error, { requestId });
    res.status(500).json({
      code: 500,
      msg: error instanceof Error ? error.message : 'Internal server error',
      data: null,
      trace_id: requestId,
      timestamp: new Date().toISOString()
    });
  }
};

/**
 * 获取实时监控数据 - SSE endpoint
 * GET /api/statistics/real-time
 * Supports Server-Sent-Events with heartbeat ping every 30 seconds
 */
export const getRealTimeStatistics = async (req: Request, res: Response) => {
  const requestId = req.headers['x-request-id'] as string || 'default';

  // Set SSE headers
  res.writeHead(200, {
    'Content-Type': 'text/event-stream',
    'Cache-Control': 'no-cache',
    'Connection': 'keep-alive',
    'X-Accel-Buffering': 'no'
  });

  logger.info('Opening SSE connection for real-time statistics', { requestId });

  // Function to send an event
  const sendEvent = (event: string, data: any) => {
    res.write(`event: ${event}\n`);
    res.write(`data: ${JSON.stringify(data)}\n\n`);
  };

  // Send initial data immediately
  try {
    const data = await statsService.getRealTimeStats();
    sendEvent('stats', data);

    // Setup heartbeat ping every 30 seconds to keep connection alive
    // Detect dead connections when client doesn't respond to ping
    const pingInterval = setInterval(() => {
      sendEvent('ping', { timestamp: new Date().toISOString() });
    }, 30000);

    // Cleanup on connection close
    req.on('close', () => {
      clearInterval(pingInterval);
      logger.info('SSE connection closed', { requestId });
    });

  } catch (error) {
    logger.error('Failed to fetch real-time statistics', error as Error, { requestId });
    sendEvent('error', {
      message: error instanceof Error ? error.message : 'Internal server error'
    });
    res.end();
  }
};
